const express = require('express');
const session = require('express-session');
const twilio = require('twilio');

// Twilio Account Settings
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// Express App Setup
const app = express();
app.use(session({
  secret: 'secret_key',
  resave: false,
  saveUninitialized: true
}));

let codes = {};

app.post('/login', (req, res) => {
  const username = req.body.username;
  const password = req.body.password;

  // Simulate user authentication logic here
  if (username === 'admin' && password === 'password') {
    const code = Math.floor(Math.random() * 900000) + 100000;
    codes[req.session.id] = code;
    sendSms(req, res, code);
  } else {
    res.status(401).send('Invalid credentials');
  }
});

app.post('/verify', (req, res) => {
  const username = req.body.username;
  const password = req.body.password;
  const code = req.body.code;

  // Simulate user authentication logic here
  if (username === 'admin' && password === 'password') {
    if (codes[req.session.id] === parseInt(code)) {
      res.send('Authentication successful');
    } else {
      res.status(401).send('Invalid code');
    }
  } else {
    res.status(401).send('Invalid credentials');
  }
});

function sendSms(req, res, code) {
  const message = new twilio.Message({
    from: 'your_twilio_number',
    to: req.body.phoneNumber,
    body: `Your MFA code is ${code}`
  });

  message.then((message) => {
    console.log(`Message sent: ${message.sid}`);
    res.send('SMS sent');
  }).done();
}

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});